                print(f"  - Pull Request: {on_config['pull_request'].get('branches', [])}")

        print("\nJobs Defined:")
        if 'jobs' in data:
            for job_name, job_config in data['jobs'].items():
                print(f"\n  Job: '{job_name}'")
