                if 'steps' in job_config:
                    print(f"    - Steps ({len(job_config['steps'])} total):")
                    for i, step in enumerate(job_config['steps'], 1):
                        if 'uses' in step:
                            print(f"        {i}. Uses: {step['uses']}")
                        elif 'run' in step:
                            print(f"        {i}. Run: {step['run']}")
                        else:
                            print(f"        {i}. {step}")

    print("\n" + "=" * 60)
    print("✓ No YAML errors detected")
    print("=" * 60)

except yaml.YAMLError as e:
    print("✗ YAML SYNTAX ERROR:")
    print(f"  {e}")
    sys.exit(1)
except Exception as e:
    print(f"✗ Error: {e}")
    sys.exit(1)
